k=KiteConnect(api_key=config.KITE_API_KEY); k.set_access_token(tok["access_token"])
VIXTOK=264969
vix={}
for a,b in [("2019-01-01","2022-06-30"),("2022-07-01","2026-06-08")]:
    for c in k.historical_data(VIXTOK, a, b, "day"):
        vix[c["date"].strftime("%Y-%m-%d")]=(c["open"],c["close"])
print("VIX days pulled:", len(vix))

def calc(rows,label):
    yr=defaultdict(float); n=defaultdict(int); eq=peak=mdd=0
    for d,p in rows: yr[d[:4]]+=p; n[d[:4]]+=1
    for d,p in rows: eq+=p; peak=max(peak,eq); mdd=min(mdd,eq-peak)
    tot=sum(p for _,p in rows); M=958020
    negs=[y for y in sorted(yr) if yr[y]<0]
    cal=(tot/7.3)/abs(mdd) if mdd else 0
    print("\n=== {}: {} trades, TOT {:,.0f}, MaxDD {:,.0f}, Calmar {:.2f}, RoM {:.1f}%/yr, neg:{}"
          .format(label,len(rows),tot,mdd,cal,tot/7.3/M*100,negs))
    for y in sorted(yr): print("   {} {:>3}t {:>12,.0f}".format(y,n[y],yr[y]))

def vix_on(d):
    if d in vix: return vix[d][0]
    base=dt.date.fromisoformat(d)
    for i in range(1,6):
        dd=(base-dt.timedelta(days=i)).isoformat()
        if dd in vix: return vix[dd][0]
    return None

print("entries w/o VIX:", [d for d,_ in W2 if vix_on(d) is None])
calc(W2,"2% base (ex-COVID), NO filter")
for floor in (12,13,14):
    calc([(d,p) for d,p in W2 if (vix_on(d) or 0)>=floor], "2% + VIX>="+str(floor))
